-- DATASOURCE: dbi:Oracle:host=192.168.101.29;sid=pean;port=1521

SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_mem_m_capital_pay ON sc_mem_m_capital_pay CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_mem_m_capital_pay() RETURNS trigger AS $BODY$
BEGIN

    if coalesce(NEW.seq_no::text, '') = '' or NEW.seq_no = 0 then
        select max(seq_no) into STRICT NEW.seq_no
        from sc_mem_m_capital_pay
        where account_year = NEW.account_year
        and membership_no = NEW.membership_no;
        NEW.seq_no := coalesce(NEW.seq_no,0) + 1;
        --Niorn 2022-12-31 Amant seq_no = 1 lock ให้ วิธีหลัก
        if NEW.seq_no = 1 then NEW.seq_no := NEW.seq_no + 1;end if;
    end if;

    if coalesce(OLD.seq_no::text, '') = '' then
        NEW.entry_date := statement_timestamp();
        NEW.entry_id := current_setting('app.login_id', true);
        NEW.entry_br := current_setting('app.login_br', true);

        --:new.post_amount := '0'; --เซตมาจาก เงินรอจ่ายคืนที่เหลือจากการชำระหนี้
    end if;

    if coalesce(NEW.post_amount::text, '') = '' then NEW.post_amount :=0;end if;
    if coalesce(NEW.post_to_fin::text, '') = '' then NEW.post_to_fin :='0';end if;

    if coalesce(trim(both NEW.group_pay_code)::text, '') = '' then NEW.group_pay_code := 'CSH';end if;
    if coalesce(trim(both NEW.ext_status)::text, '') = '' then NEW.ext_status := '0';end if;
    if coalesce(NEW.item_amount::text, '') = ''  then  NEW.item_amount := 0;end if;

    if coalesce(trim(both NEW.post_status)::text, '') = '' then NEW.post_status := 0;end if;
    if coalesce(NEW.item_div::text, '') = '' then NEW.item_div := 0;end if;
    if coalesce(NEW.item_avr::text, '') = '' then NEW.item_avr := 0;end if;
    if coalesce(NEW.item_bf_div::text, '') = '' then NEW.item_bf_div :=0;end if;
    if coalesce(NEW.item_bf_avr::text, '') = '' then NEW.item_bf_avr :=0;end if;
    if coalesce(trim(both NEW.paid_dividen)::text, '') = '' then NEW.paid_dividen := 0;end if;
    if coalesce(trim(both NEW.paid_average)::text, '') = '' then NEW.paid_average := 0;end if;

    if  trim(both NEW.post_status ) = '1' then
         NEW.post_entry_time := statement_timestamp();
         NEW.post_entry_id := current_setting('app.login_id', true);
         NEW.post_entry_pc := pka_com_login.login_pc;
         NEW.post_entry_br := current_setting('app.login_br', true);
    end if;


  --NIGHT 2021/01/25 KTM เพิ่มการเก็บ Log เกี่ยวกับวิธีรับปันผล  
    --แก้ไข วิธีรับปันผล
    if ( ( (OLD.group_pay_code IS NOT NULL AND OLD.group_pay_code::text <> '') and NEW.group_pay_code <> OLD.group_pay_code ) or ( NEW.ext_status = '1' and (NEW.group_pay_code IS NOT NULL AND NEW.group_pay_code::text <> '') ) )  then
      -- Log
      CALL pka_com_datalog.sp_set_edittime();
      CALL pka_com_datalog.sp_addlog('sc_mem_m_capital_pay','group_pay_code', OLD.group_pay_code , NEW.group_pay_code, NEW.membership_no ,NEW.account_year ,NEW.seq_no);
    end if;

    --แก้ไข ยอดปันผล
    if ( ( (OLD.item_amount IS NOT NULL AND OLD.item_amount::text <> '') and NEW.item_amount <> OLD.item_amount ) or ( NEW.ext_status = '1' and (NEW.item_amount IS NOT NULL AND NEW.item_amount::text <> '') ) )  then 
      -- Log
      CALL pka_com_datalog.sp_set_edittime();
      CALL pka_com_datalog.sp_addlog('sc_mem_m_capital_pay','item_amount', OLD.item_amount , NEW.item_amount, NEW.membership_no ,NEW.account_year ,NEW.seq_no);
    end if;

    --แก้ไข ธนาคาร
    if ( ( (OLD.bank_code IS NOT NULL AND OLD.bank_code::text <> '') and NEW.bank_code <> OLD.bank_code ) or ( NEW.ext_status = '1' and (NEW.bank_code IS NOT NULL AND NEW.bank_code::text <> '') ) )  then 
      -- Log
      CALL pka_com_datalog.sp_set_edittime();
      CALL pka_com_datalog.sp_addlog('sc_mem_m_capital_pay','bank_code', OLD.bank_code , NEW.bank_code, NEW.membership_no ,NEW.account_year ,NEW.seq_no);
    end if;

    --แก้ไข เลขบัญชี
    if ( ( (OLD.bank_acc_no IS NOT NULL AND OLD.bank_acc_no::text <> '') and NEW.bank_acc_no <> OLD.bank_acc_no ) or ( NEW.ext_status = '1' and (NEW.bank_acc_no IS NOT NULL AND NEW.bank_acc_no::text <> '') ) )  then 
      -- Log
      CALL pka_com_datalog.sp_set_edittime();
      CALL pka_com_datalog.sp_addlog('sc_mem_m_capital_pay','bank_acc_no', OLD.bank_acc_no , NEW.bank_acc_no, NEW.membership_no ,NEW.account_year ,NEW.seq_no);
    end if;
--END NIGHT 2021/01/25 KTM เพิ่มการเก็บ Log เกี่ยวกับวิธีรับปันผล  
 if coalesce(NEW.balance::text, '') = '' then NEW.balance := 0;end if;

 --Nioirn 2023-12-26 TGE ไม่ให้ยอดน้องกว่า 0
 if NEW.item_amount < 0  then
    CALL spa_dberror('T79: '||NEW.membership_no ||' Error : item_amount < 0 ');
 end if;

RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_mem_m_capital_pay() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_mem_m_capital_pay
	BEFORE INSERT OR UPDATE ON sc_mem_m_capital_pay FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_mem_m_capital_pay();

